import Link from "next/link"
import { PrismaClient } from "@prisma/client"

const prisma = new PrismaClient()

export default async function CategoriesPage() {
  const categories = await prisma.category.findMany({
    orderBy: {
      name: 'asc'
    },
    include: {
      _count: {
        select: { products: true }
      }
    }
  })

  return (
    <div className="container mx-auto px-4 md:px-6 py-12">
      <div className="mb-12">
        <h1 className="font-heading text-4xl font-bold text-ink mb-4">Browse Categories</h1>
        <p className="text-ink/70 text-lg max-w-2xl">
          Discover the best software for your business, categorized by industry and function.
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {categories.map(category => (
          <Link 
            key={category.id} 
            href={`/categories/${category.slug}`}
            className="flex items-center gap-4 p-4 rounded-xl bg-white border border-indigo/10 shadow-sm hover:border-indigo hover:shadow-md transition-all group"
          >
            <div className="w-12 h-12 shrink-0 rounded-lg bg-indigo/5 flex items-center justify-center text-indigo group-hover:bg-indigo group-hover:text-paper transition-colors">
              <span className="font-bold text-lg">{category.name.charAt(0)}</span>
            </div>
            <div>
              <h2 className="font-semibold text-ink group-hover:text-indigo transition-colors">{category.name}</h2>
              <p className="text-xs text-ink/50">{category._count.products} products</p>
            </div>
          </Link>
        ))}
      </div>
    </div>
  )
}
